#include <stdio.h>
#include <stdlib.h>

// Structure to represent a pair
typedef struct {
    int male;
    int female;
} Pair;

// Comparison function for sorting
int compare(const void *a, const void *b) {
    Pair *p1 = (Pair *)a;
    Pair *p2 = (Pair *)b;
    return p1->male - p2->male;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Pair pairs[N];
        for (int i = 0; i < N; i++) {
            scanf("%d %d", &pairs[i].male, &pairs[i].female);
        }
        qsort(pairs, N, sizeof(Pair), compare);
        long long count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (pairs[j].female < pairs[i].female) {
                    count++;
                }
            }
        }
        printf("%lld\n", count);
    }
    return 0;
}

