#include <iostream>
#include <algorithm>
using namespace std;

struct Pair {
    int male;
    int female;
};

bool compare(const Pair &p1, const Pair &p2) {
    return p1.male < p2.male;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Pair pairs[N];
        for (int i = 0; i < N; i++) {
            cin >> pairs[i].male >> pairs[i].female;
        }
        sort(pairs, pairs + N, compare);
        long long count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i + 1; j < N; j++) {
                if (pairs[j].female < pairs[i].female) {
                    count++;
                }
            }
        }
        cout << count << endl;
    }
    return 0;
}

code.Java:
import java.util.Arrays;
import java.util.Scanner;

public class Main {
    static class Pair implements Comparable<Pair> {
        int male;
        int female;
        Pair(int male, int female) {
            this.male = male;
            this.female = female;
        }
        @Override
        public int compareTo(Pair o) {
            return Integer.compare(this.male, o.male);
        }
    }
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            Pair[] pairs = new Pair[N];
            for (int i = 0; i < N; i++) {
                pairs[i] = new Pair(sc.nextInt(), sc.nextInt());
            }
            Arrays.sort(pairs);
            long long count = 0;
            for (int i = 0; i < N; i++) {
                for (int j = i + 1; j < N; j++) {
                    if (pairs[j].female < pairs[i].female) {
                        count++;
                    }
                }
            }
            System.out.println(count);
        }
    }
}

